import React, { createContext, useContext, useEffect, useMemo, useState } from 'react';
import { View, Text, TextInput, TouchableOpacity, ActivityIndicator, StyleSheet, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AUTH_STORAGE_KEY = '@auth_state_v1';

const AuthContext = createContext(null);

const mockApiLogin = async (email, password) => {
  await new Promise(resolve => setTimeout(resolve, 800));
  if (!email || !password) {
    throw new Error('Email and password are required.');
  }
  if (password.length < 4) {
    throw new Error('Invalid credentials.');
  }
  return {
    token: 'mock-jwt-token-' + Date.now(),
    user: {
      id: String(Date.now()),
      name: email.split('@')[0] || 'User',
      email,
    },
  };
};

export const AuthProvider = ({ children }) => {
  const [authLoading, setAuthLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [authToken, setAuthToken] = useState(null);
  const [user, setUser] = useState(null);

  useEffect(() => {
    const loadStoredAuth = async () => {
      try {
        const stored = await AsyncStorage.getItem(AUTH_STORAGE_KEY);
        if (stored) {
          const parsed = JSON.parse(stored);
          if (parsed?.token && parsed?.user) {
            setAuthToken(parsed.token);
            setUser(parsed.user);
            setIsAuthenticated(true);
          }
        }
      } catch (e) {
      } finally {
        setAuthLoading(false);
      }
    };
    loadStoredAuth();
  }, []);

  const signIn = async (email, password) => {
    const response = await mockApiLogin(email, password);
    const nextState = {
      token: response.token,
      user: response.user,
    };
    setAuthToken(nextState.token);
    setUser(nextState.user);
    setIsAuthenticated(true);
    await AsyncStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(nextState));
  };

  const signOut = async () => {
    setAuthToken(null);
    setUser(null);
    setIsAuthenticated(false);
    await AsyncStorage.removeItem(AUTH_STORAGE_KEY);
  };

  const value = useMemo(
    () => ({
      authLoading,
      isAuthenticated,
      authToken,
      user,
      signIn,
      signOut,
    }),
    [authLoading, isAuthenticated, authToken, user]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
};

const LoginScreen = () => {
  const { signIn } = useAuth();
  const [email, setEmail] = useState('demo@example.com');
  const [password, setPassword] = useState('1234');
  const [loading, setLoading] = useState(false);

  const onLogin = async () => {
    try {
      setLoading(true);
      await signIn(email.trim(), password);
    } catch (e) {
      Alert.alert('Login failed', e.message || 'Something went wrong.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.center}>
      <Text style={styles.title}>Sign In</Text>
      <TextInput
        value={email}
        onChangeText={setEmail}
        placeholder="Email"
        autoCapitalize="none"
        keyboardType="email-address"
        style={styles.input}
      />
      <TextInput
        value={password}
        onChangeText={setPassword}
        placeholder="Password"
        secureTextEntry
        style={styles.input}
      />
      <TouchableOpacity style={styles.button} onPress={onLogin} disabled={loading}>
        {loading ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>Login</Text>}
      </TouchableOpacity>
    </View>
  );
};

const HomeScreen = () => {
  const { user, authToken, signOut } = useAuth();

  return (
    <View style={styles.center}>
      <Text style={styles.title}>Welcome</Text>
      <Text style={styles.text}>Name: {user?.name}</Text>
      <Text style={styles.text}>Email: {user?.email}</Text>
      <Text style={styles.text} numberOfLines={1}>
        Token: {authToken}
      </Text>
      <TouchableOpacity style={styles.button} onPress={signOut}>
        <Text style={styles.buttonText}>Logout</Text>
      </TouchableOpacity>
    </View>
  );
};

const AppNavigator = () => {
  const { authLoading, isAuthenticated } = useAuth();

  if (authLoading) {
    return (
      <View style={styles.center}>
        <ActivityIndicator size="large" />
      </View>
    );
  }

  return isAuthenticated ? <HomeScreen /> : <LoginScreen />;
};

export default function App() {
  return (
    <AuthProvider>
      <AppNavigator />
    </AuthProvider>
  );
}

